args.sparql:
SELECT ?pm ?pmLabel ?reason
WHERE {
  VALUES ?pm { wd:Q272201 wd:Q180589 wd:Q264766 wd:Q192 }
  ?pm p:P39 ?position .
  ?position ps:P39 wd:Q19089 .
  ?position pq:P5521 ?reason .
  ?pm rdfs:label ?pmLabel .
  FILTER(LANG(?pmLabel) = "en")
}

SELECT DISTINCT ?pm ?pmLabel ?event ?eventLabel
WHERE {
  VALUES ?pm { wd:Q272201 wd:Q180589 wd:Q264766 wd:Q192 }
  ?pm wdt:P1344 ?event .
  ?event rdfs:label ?eventLabel .
  FILTER(LANG(?eventLabel) = "en")
  ?pm rdfs:label ?pmLabel .
  FILTER(LANG(?pmLabel) = "en")
}
ORDER BY ?pm

