SELECT DISTINCT ?pm ?pmLabel ?reason ?reasonLabel
WHERE {
  VALUES ?pm { wd:Q272201 wd:Q180589 wd:Q264766 wd:Q192 }
  ?pm rdfs:label ?pmLabel .
  FILTER(LANG(?pmLabel) = "en")
  {
    ?pm p:P39 ?position .
    ?position ps:P39 wd:Q19089 ;
               pq:P5823 ?reason .
    ?reason rdfs:label ?reasonLabel .
    FILTER(LANG(?reasonLabel) = "en")
  }
  UNION
  {
    ?pm wdt:P793 ?reason .
    ?reason rdfs:label ?reasonLabel .
    FILTER(LANG(?reasonLabel) = "en")
  }
  FILTER REGEX(?reasonLabel, "resignation|crisis|scandal|vote|referendum|brexit|confidence|october|2022|2016|negotiations|leadership|Green", "i")
}
ORDER BY ?pm
